85	func executeBeadWorktreeGitDir(wtPath string) (string, error) {
86		gitMetaPath := filepath.Join(wtPath, ".git")
87		info, err := os.Stat(gitMetaPath)
88		if err != nil {
89			return "", fmt.Errorf("stat worktree .git: %w", err)
90		}
91		if info.IsDir() {
92			return gitMetaPath, nil
93		}
94	
95		raw, err := os.ReadFile(gitMetaPath)
96		if err != nil {
97			return "", fmt.Errorf("read worktree .git file: %w", err)
98		}
99		line := strings.TrimSpace(string(raw))
100		const prefix = "gitdir:"
101		if !strings.HasPrefix(line, prefix) {
102			return "", fmt.Errorf("worktree .git file missing gitdir prefix: %q", line)
103		}
104		gitDir := strings.TrimSpace(strings.TrimPrefix(line, prefix))
105		if !filepath.IsAbs(gitDir) {
106			gitDir = filepath.Clean(filepath.Join(wtPath, gitDir))
107		}
