201	
202	  if (( dangerous_key == 1 )); then
203	    if (( repo_scope_idx >= 0 )); then
204	      suffix[$repo_scope_idx]=--file
205	      suffix=("${suffix[@]:0:repo_scope_idx+1}" "$private_cfg" "${suffix[@]:repo_scope_idx+1}")
206	    elif (( explicit_scope == 0 )); then
